/**
 * Material Routes
 *
 * REST endpoints for inventory positions and material reservations.
 * Materials are a constraint for PM scheduling - PMs cannot proceed without
 * required blocking parts.
 *
 * Key features:
 * - Inventory positions with filtering (depot, part number, low stock)
 * - Material reservations with filtering (PM, status)
 * - Reservation fulfillment workflow
 *
 * @see specs/005-api.md Section 5.11
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  ErrorCodes,
  parsePaginationQuery,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import { getMaterialService, type ReservationStatus } from '../../services';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let materialService: ReturnType<typeof getMaterialService> | null = null;

function getService(): ReturnType<typeof getMaterialService> {
  if (!materialService) {
    materialService = getMaterialService();
  }
  return materialService;
}

export const materialRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Inventory Endpoints
// =============================================================================

/**
 * GET /materials/inventory
 *
 * Get inventory positions with filtering.
 *
 * Query Parameters:
 * - depotId: Filter by depot (UUID)
 * - partNumber: Filter by part number (partial match)
 * - lowStock: Only show low stock items (boolean)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 *
 * @returns Paginated list of inventory positions with depot info
 */
materialRoutes.get('/materials/inventory', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  // Parse query parameters
  const depotId = c.req.query('depotId');
  const partNumber = c.req.query('partNumber');
  const lowStockParam = c.req.query('lowStock');

  // Validate depotId if provided
  if (depotId && !isValidUuid(depotId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid depotId format', requestId),
      400
    );
  }

  // Parse boolean
  const lowStock = lowStockParam === 'true';

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  const result = await service.listInventory(
    {
      depotId: depotId || undefined,
      partNumber: partNumber || undefined,
      lowStock: lowStockParam !== undefined ? lowStock : undefined,
    },
    { page: pagination.page, pageSize: pagination.pageSize }
  );

  // Map to API response format per spec 005.11
  const items = result.items.map((item) => ({
    id: item.id,
    depotId: item.depotId,
    depotCode: item.depotCode,
    partNumber: item.partNumber,
    partDescription: item.partDescription,
    quantityOnHand: item.quantityOnHand,
    quantityReserved: item.quantityReserved,
    quantityAvailable: item.quantityAvailable,
    quantityOnOrder: item.quantityOnOrder,
    reorderPoint: item.reorderPoint,
    nextDeliveryDate: item.nextDeliveryDate,
    unitCost: item.unitCost,
    lastSyncAt: item.lastSyncAt,
  }));

  return c.json(
    paginatedSuccess(items, {
      page: result.page,
      pageSize: result.pageSize,
      totalItems: result.total,
    }, { durationMs: getRequestDuration(c) })
  );
});

/**
 * GET /materials/inventory/:id
 *
 * Get a single inventory position by ID.
 *
 * @returns Inventory position with depot info
 */
materialRoutes.get('/materials/inventory/:id', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();
  const id = c.req.param('id');

  // Validate UUID
  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid inventory ID format', requestId),
      400
    );
  }

  try {
    const item = await service.getInventoryById(id);

    return c.json(
      success(
        {
          id: item.id,
          depotId: item.depotId,
          depotCode: item.depotCode,
          partNumber: item.partNumber,
          partDescription: item.partDescription,
          quantityOnHand: item.quantityOnHand,
          quantityReserved: item.quantityReserved,
          quantityAvailable: item.quantityAvailable,
          quantityOnOrder: item.quantityOnOrder,
          reorderPoint: item.reorderPoint,
          reorderQuantity: item.reorderQuantity,
          nextDeliveryDate: item.nextDeliveryDate,
          nextDeliveryQuantity: item.nextDeliveryQuantity,
          unitCost: item.unitCost,
          currency: item.currency,
          lastSyncAt: item.lastSyncAt,
          sourceSystem: item.sourceSystem,
          isLowStock: item.isLowStock,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  } catch (err) {
    if (err instanceof Error && err.name === 'NotFoundError') {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Inventory position not found: ${id}`, requestId),
        404
      );
    }
    throw err;
  }
});

/**
 * GET /materials/inventory/summary
 *
 * Get inventory summary statistics.
 *
 * @returns Aggregate stats including low stock counts per depot
 */
materialRoutes.get('/materials/inventory/summary', async (c) => {
  const service = getService();

  const summary = await service.getInventorySummary();

  return c.json(
    success(summary, { timing: { durationMs: getRequestDuration(c) } })
  );
});

// =============================================================================
// Reservation Endpoints
// =============================================================================

/**
 * GET /materials/reservations
 *
 * Get material reservations with filtering.
 *
 * Query Parameters:
 * - pmScheduleId: Filter by PM (UUID)
 * - status: Filter by status (PENDING, FULFILLED, EXPIRED)
 * - depotId: Filter by depot (UUID)
 * - partNumber: Filter by part number
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 *
 * @returns Paginated list of reservations with PM and depot details
 */
materialRoutes.get('/materials/reservations', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();

  // Parse query parameters
  const pmScheduleId = c.req.query('pmScheduleId');
  const status = c.req.query('status') as ReservationStatus | undefined;
  const depotId = c.req.query('depotId');
  const partNumber = c.req.query('partNumber');

  // Validate UUIDs if provided
  if (pmScheduleId && !isValidUuid(pmScheduleId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid pmScheduleId format', requestId),
      400
    );
  }

  if (depotId && !isValidUuid(depotId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid depotId format', requestId),
      400
    );
  }

  // Validate status if provided
  if (status && !['PENDING', 'FULFILLED', 'EXPIRED'].includes(status)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        'status must be one of: PENDING, FULFILLED, EXPIRED',
        requestId
      ),
      400
    );
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  const result = await service.listReservations(
    {
      pmScheduleId: pmScheduleId || undefined,
      status: status || undefined,
      depotId: depotId || undefined,
      partNumber: partNumber || undefined,
    },
    { page: pagination.page, pageSize: pagination.pageSize }
  );

  // Map to API response format per spec 005.11
  const items = result.items.map((item) => ({
    id: item.id,
    pmScheduleId: item.pmScheduleId,
    partNumber: item.partNumber,
    quantityReserved: item.quantityReserved,
    reservationType: item.reservationType,
    reservedAt: item.reservedAt,
    expiresAt: item.expiresAt,
    fulfilledAt: item.fulfilledAt,
    fulfilledQuantity: item.fulfilledQuantity,
    status: item.status,
    pm: item.pm,
    depot: item.depot,
    reservedBy: item.reservedByName,
  }));

  return c.json(
    paginatedSuccess(items, {
      page: result.page,
      pageSize: result.pageSize,
      totalItems: result.total,
    }, { durationMs: getRequestDuration(c) })
  );
});

/**
 * GET /materials/reservations/:id
 *
 * Get a single reservation by ID.
 *
 * @returns Reservation with details
 */
materialRoutes.get('/materials/reservations/:id', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();
  const id = c.req.param('id');

  // Validate UUID
  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid reservation ID format', requestId),
      400
    );
  }

  try {
    const item = await service.getReservationById(id);

    return c.json(
      success(
        {
          id: item.id,
          pmScheduleId: item.pmScheduleId,
          inventoryPositionId: item.inventoryPositionId,
          partNumber: item.partNumber,
          quantityReserved: item.quantityReserved,
          reservationType: item.reservationType,
          reservedAt: item.reservedAt,
          reservedBy: item.reservedByName,
          expiresAt: item.expiresAt,
          fulfilledAt: item.fulfilledAt,
          fulfilledQuantity: item.fulfilledQuantity,
          status: item.status,
          pm: item.pm,
          depot: item.depot,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  } catch (err) {
    if (err instanceof Error && err.name === 'NotFoundError') {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Reservation not found: ${id}`, requestId),
        404
      );
    }
    throw err;
  }
});

/**
 * POST /materials/reservations/:id/fulfill
 *
 * Mark a reservation as fulfilled.
 *
 * Request body (optional):
 * - fulfilledQuantity: Quantity actually delivered (defaults to reserved quantity)
 *
 * @returns Updated reservation with fulfillment details
 */
materialRoutes.post('/materials/reservations/:id/fulfill', async (c) => {
  const requestId = getRequestId(c);
  const service = getService();
  const id = c.req.param('id');

  // Validate UUID
  if (!isValidUuid(id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid reservation ID format', requestId),
      400
    );
  }

  // Parse request body (optional)
  let fulfilledQuantity: number | undefined;
  try {
    const body = await c.req.json().catch(() => ({}));
    if (body.fulfilledQuantity !== undefined) {
      if (typeof body.fulfilledQuantity !== 'number' || body.fulfilledQuantity < 0) {
        return c.json(
          error(
            ErrorCodes.VALIDATION_ERROR,
            'fulfilledQuantity must be a non-negative number',
            requestId
          ),
          400
        );
      }
      fulfilledQuantity = body.fulfilledQuantity;
    }
  } catch {
    // Empty body is fine
  }

  try {
    // Get user ID from context if available
    const user = c.get('user');
    const userId = user?.id;

    const result = await service.fulfillReservation({
      reservationId: id,
      fulfilledQuantity,
      userId,
    });

    return c.json(
      success(
        {
          id: result.id,
          partNumber: result.partNumber,
          quantityReserved: result.quantityReserved,
          fulfilledQuantity: result.fulfilledQuantity,
          fulfilledAt: result.fulfilledAt,
          status: result.status,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  } catch (err) {
    if (err instanceof Error) {
      if (err.name === 'NotFoundError') {
        return c.json(
          error(ErrorCodes.NOT_FOUND, `Reservation not found: ${id}`, requestId),
          404
        );
      }
      if (err.name === 'ValidationError') {
        const validationErr = err as Error & { context?: { code?: string } };
        const errorCode = validationErr.context?.code;
        if (errorCode === 'ALREADY_FULFILLED') {
          return c.json(
            error(ErrorCodes.CONFLICT, 'Reservation is already fulfilled', requestId),
            409
          );
        }
        if (errorCode === 'RESERVATION_EXPIRED') {
          return c.json(
            error(
              ErrorCodes.CONFLICT,
              'Cannot fulfill an expired reservation',
              requestId
            ),
            409
          );
        }
      }
    }
    throw err;
  }
});

/**
 * MMS Material Management Tables
 *
 * Inventory tracking and material reservations for PM scheduling.
 * Materials are a constraint for PM scheduling - PMs cannot proceed
 * without required blocking parts.
 *
 * Integration:
 * - Inventory snapshots come from Maximo/ERP daily
 * - Reservations are created when PMs are scheduled
 * - Soft reservations auto-expire if PM moves
 *
 * @see specs/003-database-schema.md Section 3.6
 */

import { relations, sql } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';
import { reservationTypeEnum } from './enums';
import { pmSchedule } from './pm-management';
import { users } from './users';

/**
 * Inventory Positions - Current stock levels
 *
 * Snapshot of inventory from ERP/Maximo system.
 * Updated daily via integration sync.
 *
 * Key fields:
 * - quantity_available: Calculated as on_hand - reserved
 * - reorder_point: Triggers replenishment when available drops below
 */
export const inventoryPositions = pgTable(
  'inventory_positions',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id')
      .notNull()
      .references(() => depots.id),
    partNumber: varchar('part_number', { length: 50 }).notNull(),
    partDescription: text('part_description'),

    // Quantities
    quantityOnHand: integer('quantity_on_hand').notNull().default(0),
    quantityReserved: integer('quantity_reserved').notNull().default(0),
    quantityOnOrder: integer('quantity_on_order').default(0),
    // Generated column: available inventory for scheduling
    quantityAvailable: integer('quantity_available').generatedAlwaysAs(
      sql`quantity_on_hand - quantity_reserved`
    ),

    // Replenishment
    reorderPoint: integer('reorder_point'),
    reorderQuantity: integer('reorder_quantity'),
    nextDeliveryDate: date('next_delivery_date'),
    nextDeliveryQuantity: integer('next_delivery_quantity'),

    // Cost
    unitCost: decimal('unit_cost', { precision: 12, scale: 2 }),
    currency: varchar('currency', { length: 3 }).default('SGD'),

    // Sync tracking
    lastSyncAt: timestamp('last_sync_at', { withTimezone: true }),
    sourceSystem: varchar('source_system', { length: 50 }).default('MAXIMO'),

    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_inventory_depot_part').on(table.depotId, table.partNumber),
    index('idx_inventory_depot').on(table.depotId),
    index('idx_inventory_part').on(table.partNumber),
  ]
);

/**
 * Material Reservations - Links inventory to PM schedules
 *
 * Two reservation types:
 * - SOFT: Tentative, auto-expires if PM moves (90-day soft constraint)
 * - HARD: Committed, parts allocated (14-day hard constraint)
 *
 * Constraint enforcement:
 * - BLOCKING parts with SOFT reservation: Warning, PM can proceed
 * - BLOCKING parts without reservation: PM cannot be scheduled
 */
export const materialReservations = pgTable(
  'material_reservations',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmScheduleId: uuid('pm_schedule_id')
      .notNull()
      .references(() => pmSchedule.id, { onDelete: 'cascade' }),
    inventoryPositionId: uuid('inventory_position_id')
      .notNull()
      .references(() => inventoryPositions.id),
    partNumber: varchar('part_number', { length: 50 }).notNull(),

    quantityReserved: integer('quantity_reserved').notNull(),
    reservationType: reservationTypeEnum('reservation_type').default('SOFT'),

    reservedAt: timestamp('reserved_at', { withTimezone: true }).defaultNow(),
    reservedBy: uuid('reserved_by').references(() => users.id),
    expiresAt: timestamp('expires_at', { withTimezone: true }), // SOFT reservations auto-expire

    // Fulfillment
    fulfilledAt: timestamp('fulfilled_at', { withTimezone: true }),
    fulfilledQuantity: integer('fulfilled_quantity'),
  },
  (table) => [
    uniqueIndex('idx_reservations_pm_part').on(table.pmScheduleId, table.partNumber),
    index('idx_reservations_pm').on(table.pmScheduleId),
    index('idx_reservations_inventory').on(table.inventoryPositionId),
    index('idx_reservations_expiring').on(table.expiresAt),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const inventoryPositionsRelations = relations(inventoryPositions, ({ one, many }) => ({
  depot: one(depots, {
    fields: [inventoryPositions.depotId],
    references: [depots.id],
  }),
  reservations: many(materialReservations),
}));

export const materialReservationsRelations = relations(materialReservations, ({ one }) => ({
  pmScheduleRecord: one(pmSchedule, {
    fields: [materialReservations.pmScheduleId],
    references: [pmSchedule.id],
  }),
  inventoryPosition: one(inventoryPositions, {
    fields: [materialReservations.inventoryPositionId],
    references: [inventoryPositions.id],
  }),
  reservedByUser: one(users, {
    fields: [materialReservations.reservedBy],
    references: [users.id],
  }),
}));

