   283→
   284→      return {
   285→        items,
   286→        total,
   287→        page: pagination.page,
   288→        pageSize: pagination.pageSize,
   289→        totalPages: Math.ceil(total / pagination.pageSize),
   290→      };
   291→    });
   292→  }
   293→
   294→  /**
   295→   * Get a single inventory position by ID
   296→   *
   297→   * @param id - Inventory position ID
   298→   * @returns Inventory position with depot info
   299→   * @throws NotFoundError if not found
   300→   */
   301→  async getInventoryById(id: string): Promise<InventoryWithDepot> {
   302→    return this.traced('getInventoryById', async (span) => {
   303→      span.setAttribute('inventory.id', id);
   304→
   305→      const result = await this.db
   306→        .select({
   307→          id: inventoryPositions.id,
   308→          depotId: inventoryPositions.depotId,
   309→          depotCode: depots.code,
   310→          depotName: depots.name,
   311→          partNumber: inventoryPositions.partNumber,
   312→          partDescription: inventoryPositions.partDescription,
   313→          quantityOnHand: inventoryPositions.quantityOnHand,
   314→          quantityReserved: inventoryPositions.quantityReserved,
   315→          quantityOnOrder: inventoryPositions.quantityOnOrder,
   316→          reorderPoint: inventoryPositions.reorderPoint,
   317→          reorderQuantity: inventoryPositions.reorderQuantity,
   318→          nextDeliveryDate: inventoryPositions.nextDeliveryDate,
   319→          nextDeliveryQuantity: inventoryPositions.nextDeliveryQuantity,
   320→          unitCost: inventoryPositions.unitCost,
   321→          currency: inventoryPositions.currency,
   322→          lastSyncAt: inventoryPositions.lastSyncAt,
   323→          sourceSystem: inventoryPositions.sourceSystem,
   324→        })
   325→        .from(inventoryPositions)
   326→        .innerJoin(depots, eq(inventoryPositions.depotId, depots.id))
   327→        .where(eq(inventoryPositions.id, id))
   328→        .limit(1);
   329→
   330→      if (result.length === 0) {
   331→        throw new NotFoundError(`Inventory position not found: ${id}`);
   332→      }
   333→
   334→      const row = result[0];
   335→      const quantityAvailable = row.quantityOnHand - row.quantityReserved;
   336→      const isLowStock =
   337→        row.reorderPoint !== null && quantityAvailable <= row.reorderPoint;
   338→
   339→      return {
   340→        id: row.id,
   341→        depotId: row.depotId,
   342→        depotCode: row.depotCode,
   343→        depotName: row.depotName,
   344→        partNumber: row.partNumber,
   345→        partDescription: row.partDescription,
   346→        quantityOnHand: row.quantityOnHand,
   347→        quantityReserved: row.quantityReserved,
   348→        quantityAvailable,
   349→        quantityOnOrder: row.quantityOnOrder,
   350→        reorderPoint: row.reorderPoint,
   351→        reorderQuantity: row.reorderQuantity,
   352→        nextDeliveryDate: row.nextDeliveryDate,
   353→        nextDeliveryQuantity: row.nextDeliveryQuantity,
   354→        unitCost: row.unitCost ? Number(row.unitCost) : null,
   355→        currency: row.currency,
   356→        lastSyncAt: row.lastSyncAt?.toISOString() || null,
   357→        sourceSystem: row.sourceSystem,
   358→        isLowStock,
   359→      };
   360→    });
   361→  }
