/**
 * MMS Material Service
 *
 * Manages inventory positions and material reservations for PM scheduling.
 * Materials are a constraint for PM scheduling - PMs cannot proceed without
 * required blocking parts.
 *
 * Key responsibilities:
 * - Query inventory positions with filtering (depot, part number, low stock)
 * - Query material reservations with filtering (PM, status)
 * - Fulfill material reservations (mark as delivered)
 * - Support soft/hard reservation lifecycle
 *
 * Integration:
 * - Inventory snapshots come from Maximo/ERP daily
 * - Reservations are created when PMs are scheduled
 * - Soft reservations auto-expire if PM moves
 *
 * Constraint enforcement:
 * - BLOCKING parts with SOFT reservation: Warning, PM can proceed
 * - BLOCKING parts without reservation: PM cannot be scheduled
 *
 * @see specs/004-domain-services.md
 * @see specs/005-api.md Section 5.11
 */

import { eq, and, sql, desc, type SQL } from 'drizzle-orm';
import { BaseService } from '../lib/services/base';
import {
  inventoryPositions,
  materialReservations,
  depots,
  pmSchedule,
  pmTypes,
  trains,
  users,
} from '../lib/db/schema';
import { NotFoundError, ValidationError } from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Inventory position with depot info */
export interface InventoryWithDepot {
  id: string;
  depotId: string;
  depotCode: string;
  depotName: string;
  partNumber: string;
  partDescription: string | null;
  quantityOnHand: number;
  quantityReserved: number;
  quantityAvailable: number;
  quantityOnOrder: number | null;
  reorderPoint: number | null;
  reorderQuantity: number | null;
  nextDeliveryDate: string | null;
  nextDeliveryQuantity: number | null;
  unitCost: number | null;
  currency: string | null;
  lastSyncAt: string | null;
  sourceSystem: string | null;
  isLowStock: boolean;
}

/** Reservation status for filtering */
export type ReservationStatus = 'PENDING' | 'FULFILLED' | 'EXPIRED';

/** Material reservation with related info */
export interface ReservationWithDetails {
  id: string;
  pmScheduleId: string;
  inventoryPositionId: string;
  partNumber: string;
  quantityReserved: number;
  reservationType: 'SOFT' | 'HARD';
  reservedAt: string;
  reservedBy: string | null;
  reservedByName: string | null;
  expiresAt: string | null;
  fulfilledAt: string | null;
  fulfilledQuantity: number | null;
  status: ReservationStatus;
  pm: {
    id: string;
    trainNumber: string;
    pmCode: string;
    targetDate: string;
  };
  depot: {
    id: string;
    code: string;
    name: string;
  };
}

/** Filters for inventory listing */
export interface InventoryFilters {
  depotId?: string;
  partNumber?: string;
  lowStock?: boolean;
}

/** Filters for reservation listing */
export interface ReservationFilters {
  pmScheduleId?: string;
  status?: ReservationStatus;
  depotId?: string;
  partNumber?: string;
}

/** Pagination options */
export interface PaginationOptions {
  page: number;
  pageSize: number;
}

/** Paginated result */
export interface PaginatedResult<T> {
  items: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** Fulfill reservation request */
export interface FulfillReservationRequest {
  reservationId: string;
  fulfilledQuantity?: number;
  userId?: string;
}

/** Fulfill reservation result */
export interface FulfillReservationResult {
  id: string;
  partNumber: string;
  quantityReserved: number;
  fulfilledQuantity: number;
  fulfilledAt: string;
  status: ReservationStatus;
}

// =============================================================================
// Singleton Instance
// =============================================================================

let instance: MaterialService | null = null;

/**
 * Get the singleton MaterialService instance
 */
export function getMaterialService(): MaterialService {
  if (!instance) {
    instance = new MaterialService();
  }
  return instance;
}

// =============================================================================
// Service Implementation
// =============================================================================

/**
 * Material Service
 *
 * Manages inventory and material reservations for PM scheduling.
 */
export class MaterialService extends BaseService {
  constructor() {
    super({ name: 'material-service' });
  }

  /**
   * List inventory positions with filtering
   *
   * Supports filtering by:
   * - depotId: Filter by specific depot
   * - partNumber: Filter by exact or partial part number
   * - lowStock: Only show items where available <= reorder point
   *
   * @param filters - Query filters
   * @param pagination - Pagination options
   * @returns Paginated list of inventory positions with depot info
   */
  async listInventory(
    filters: InventoryFilters = {},
    pagination: PaginationOptions = { page: 1, pageSize: 50 }
  ): Promise<PaginatedResult<InventoryWithDepot>> {
    return this.traced('listInventory', async (span) => {
      span.setAttribute('filters.depotId', filters.depotId || '');
      span.setAttribute('filters.partNumber', filters.partNumber || '');
      span.setAttribute('filters.lowStock', filters.lowStock || false);
      span.setAttribute('pagination.page', pagination.page);
      span.setAttribute('pagination.pageSize', pagination.pageSize);

      const offset = (pagination.page - 1) * pagination.pageSize;

      // Build dynamic where conditions
      const conditions: SQL<unknown>[] = [];

      if (filters.depotId) {
        conditions.push(eq(inventoryPositions.depotId, filters.depotId));
      }

      if (filters.partNumber) {
        conditions.push(
          sql`${inventoryPositions.partNumber} ILIKE ${`%${filters.partNumber}%`}`
        );
      }

      // Execute query with joins
      const query = this.db
        .select({
          id: inventoryPositions.id,
          depotId: inventoryPositions.depotId,
          depotCode: depots.code,
          depotName: depots.name,
          partNumber: inventoryPositions.partNumber,
          partDescription: inventoryPositions.partDescription,
          quantityOnHand: inventoryPositions.quantityOnHand,
          quantityReserved: inventoryPositions.quantityReserved,
          quantityOnOrder: inventoryPositions.quantityOnOrder,
          reorderPoint: inventoryPositions.reorderPoint,
          reorderQuantity: inventoryPositions.reorderQuantity,
          nextDeliveryDate: inventoryPositions.nextDeliveryDate,
          nextDeliveryQuantity: inventoryPositions.nextDeliveryQuantity,
          unitCost: inventoryPositions.unitCost,
          currency: inventoryPositions.currency,
          lastSyncAt: inventoryPositions.lastSyncAt,
          sourceSystem: inventoryPositions.sourceSystem,
        })
        .from(inventoryPositions)
        .innerJoin(depots, eq(inventoryPositions.depotId, depots.id))
        .where(conditions.length > 0 ? and(...conditions) : undefined);

      // For lowStock filter, we need to do it post-query since it's a computed field
      const allResults = await query;

      // Calculate available quantity and filter by low stock if needed
      let filteredResults = allResults.map((row) => ({
        ...row,
        quantityAvailable: row.quantityOnHand - row.quantityReserved,
        isLowStock:
          row.reorderPoint !== null &&
          row.quantityOnHand - row.quantityReserved <= row.reorderPoint,
      }));

      if (filters.lowStock) {
        filteredResults = filteredResults.filter((r) => r.isLowStock);
      }

      // Apply pagination
      const total = filteredResults.length;
      const paginatedItems = filteredResults.slice(offset, offset + pagination.pageSize);

      // Format response
      const items: InventoryWithDepot[] = paginatedItems.map((row) => ({
        id: row.id,
        depotId: row.depotId,
        depotCode: row.depotCode,
        depotName: row.depotName,
        partNumber: row.partNumber,
        partDescription: row.partDescription,
        quantityOnHand: row.quantityOnHand,
        quantityReserved: row.quantityReserved,
        quantityAvailable: row.quantityAvailable,
        quantityOnOrder: row.quantityOnOrder,
        reorderPoint: row.reorderPoint,
        reorderQuantity: row.reorderQuantity,
        nextDeliveryDate: row.nextDeliveryDate,
        nextDeliveryQuantity: row.nextDeliveryQuantity,
        unitCost: row.unitCost ? Number(row.unitCost) : null,
        currency: row.currency,
        lastSyncAt: row.lastSyncAt?.toISOString() || null,
        sourceSystem: row.sourceSystem,
        isLowStock: row.isLowStock,
      }));

      span.setAttribute('result.count', items.length);
      span.setAttribute('result.total', total);

      return {
        items,
        total,
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalPages: Math.ceil(total / pagination.pageSize),
      };
    });
  }

  /**
   * Get a single inventory position by ID
   *
   * @param id - Inventory position ID
   * @returns Inventory position with depot info
   * @throws NotFoundError if not found
   */
  async getInventoryById(id: string): Promise<InventoryWithDepot> {
    return this.traced('getInventoryById', async (span) => {
      span.setAttribute('inventory.id', id);

      const result = await this.db
        .select({
          id: inventoryPositions.id,
          depotId: inventoryPositions.depotId,
          depotCode: depots.code,
          depotName: depots.name,
          partNumber: inventoryPositions.partNumber,
          partDescription: inventoryPositions.partDescription,
          quantityOnHand: inventoryPositions.quantityOnHand,
          quantityReserved: inventoryPositions.quantityReserved,
          quantityOnOrder: inventoryPositions.quantityOnOrder,
          reorderPoint: inventoryPositions.reorderPoint,
          reorderQuantity: inventoryPositions.reorderQuantity,
          nextDeliveryDate: inventoryPositions.nextDeliveryDate,
          nextDeliveryQuantity: inventoryPositions.nextDeliveryQuantity,
          unitCost: inventoryPositions.unitCost,
          currency: inventoryPositions.currency,
          lastSyncAt: inventoryPositions.lastSyncAt,
          sourceSystem: inventoryPositions.sourceSystem,
        })
        .from(inventoryPositions)
        .innerJoin(depots, eq(inventoryPositions.depotId, depots.id))
        .where(eq(inventoryPositions.id, id))
        .limit(1);

      if (result.length === 0) {
        throw new NotFoundError(`Inventory position not found: ${id}`);
      }

      const row = result[0];
      const quantityAvailable = row.quantityOnHand - row.quantityReserved;
      const isLowStock =
        row.reorderPoint !== null && quantityAvailable <= row.reorderPoint;

      return {
        id: row.id,
        depotId: row.depotId,
        depotCode: row.depotCode,
        depotName: row.depotName,
        partNumber: row.partNumber,
        partDescription: row.partDescription,
        quantityOnHand: row.quantityOnHand,
        quantityReserved: row.quantityReserved,
        quantityAvailable,
        quantityOnOrder: row.quantityOnOrder,
        reorderPoint: row.reorderPoint,
        reorderQuantity: row.reorderQuantity,
        nextDeliveryDate: row.nextDeliveryDate,
        nextDeliveryQuantity: row.nextDeliveryQuantity,
        unitCost: row.unitCost ? Number(row.unitCost) : null,
        currency: row.currency,
        lastSyncAt: row.lastSyncAt?.toISOString() || null,
        sourceSystem: row.sourceSystem,
        isLowStock,
      };
    });
  }

  /**
   * List material reservations with filtering
   *
   * Supports filtering by:
   * - pmScheduleId: Filter by specific PM
   * - status: PENDING, FULFILLED, or EXPIRED
   * - depotId: Filter by depot
   * - partNumber: Filter by part number
   *
   * @param filters - Query filters
   * @param pagination - Pagination options
   * @returns Paginated list of reservations with PM and depot details
   */
  async listReservations(
    filters: ReservationFilters = {},
    pagination: PaginationOptions = { page: 1, pageSize: 50 }
  ): Promise<PaginatedResult<ReservationWithDetails>> {
    return this.traced('listReservations', async (span) => {
      span.setAttribute('filters.pmScheduleId', filters.pmScheduleId || '');
      span.setAttribute('filters.status', filters.status || '');
      span.setAttribute('pagination.page', pagination.page);
      span.setAttribute('pagination.pageSize', pagination.pageSize);

      const offset = (pagination.page - 1) * pagination.pageSize;
      const now = new Date();

      // Build dynamic where conditions
      const conditions: SQL<unknown>[] = [];

      if (filters.pmScheduleId) {
        conditions.push(eq(materialReservations.pmScheduleId, filters.pmScheduleId));
      }

      if (filters.partNumber) {
        conditions.push(eq(materialReservations.partNumber, filters.partNumber));
      }

      // Execute query with joins
      const results = await this.db
        .select({
          id: materialReservations.id,
          pmScheduleId: materialReservations.pmScheduleId,
          inventoryPositionId: materialReservations.inventoryPositionId,
          partNumber: materialReservations.partNumber,
          quantityReserved: materialReservations.quantityReserved,
          reservationType: materialReservations.reservationType,
          reservedAt: materialReservations.reservedAt,
          reservedBy: materialReservations.reservedBy,
          expiresAt: materialReservations.expiresAt,
          fulfilledAt: materialReservations.fulfilledAt,
          fulfilledQuantity: materialReservations.fulfilledQuantity,
          pmTargetDate: pmSchedule.targetDate,
          trainId: pmSchedule.trainId,
          trainNumber: trains.trainNumber,
          pmTypeId: pmSchedule.pmTypeId,
          pmCode: pmTypes.pmCode,
          depotId: pmSchedule.assignedDepotId,
          depotCode: depots.code,
          depotName: depots.name,
          reservedByFirstName: users.firstName,
          reservedByLastName: users.lastName,
        })
        .from(materialReservations)
        .innerJoin(pmSchedule, eq(materialReservations.pmScheduleId, pmSchedule.id))
        .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
        .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
        .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
        .leftJoin(users, eq(materialReservations.reservedBy, users.id))
        .where(conditions.length > 0 ? and(...conditions) : undefined)
        .orderBy(desc(materialReservations.reservedAt));

      // Calculate status and filter
      let processedResults = results.map((row) => {
        let status: ReservationStatus;
        if (row.fulfilledAt) {
          status = 'FULFILLED';
        } else if (row.expiresAt && new Date(row.expiresAt) < now) {
          status = 'EXPIRED';
        } else {
          status = 'PENDING';
        }

        return {
          ...row,
          status,
        };
      });

      // Filter by status if specified
      if (filters.status) {
        processedResults = processedResults.filter((r) => r.status === filters.status);
      }

      // Filter by depot if specified
      if (filters.depotId) {
        processedResults = processedResults.filter((r) => r.depotId === filters.depotId);
      }

      // Apply pagination
      const total = processedResults.length;
      const paginatedItems = processedResults.slice(offset, offset + pagination.pageSize);

      // Format response
      const items: ReservationWithDetails[] = paginatedItems.map((row) => ({
        id: row.id,
        pmScheduleId: row.pmScheduleId,
        inventoryPositionId: row.inventoryPositionId,
        partNumber: row.partNumber,
        quantityReserved: row.quantityReserved,
        reservationType: row.reservationType as 'SOFT' | 'HARD',
        reservedAt: row.reservedAt?.toISOString() || '',
        reservedBy: row.reservedBy,
        reservedByName:
          row.reservedByFirstName && row.reservedByLastName
            ? `${row.reservedByFirstName} ${row.reservedByLastName}`
            : null,
        expiresAt: row.expiresAt?.toISOString() || null,
        fulfilledAt: row.fulfilledAt?.toISOString() || null,
        fulfilledQuantity: row.fulfilledQuantity,
        status: row.status,
        pm: {
          id: row.pmScheduleId,
          trainNumber: row.trainNumber,
          pmCode: row.pmCode,
          targetDate: row.pmTargetDate,
        },
        depot: {
          id: row.depotId || '',
          code: row.depotCode || '',
          name: row.depotName || '',
        },
      }));

      span.setAttribute('result.count', items.length);
      span.setAttribute('result.total', total);

      return {
        items,
        total,
        page: pagination.page,
        pageSize: pagination.pageSize,
        totalPages: Math.ceil(total / pagination.pageSize),
      };
    });
  }

  /**
   * Get a single reservation by ID
   *
   * @param id - Reservation ID
   * @returns Reservation with details
   * @throws NotFoundError if not found
   */
  async getReservationById(id: string): Promise<ReservationWithDetails> {
    return this.traced('getReservationById', async (span) => {
      span.setAttribute('reservation.id', id);

      const now = new Date();

      const results = await this.db
        .select({
          id: materialReservations.id,
          pmScheduleId: materialReservations.pmScheduleId,
          inventoryPositionId: materialReservations.inventoryPositionId,
          partNumber: materialReservations.partNumber,
          quantityReserved: materialReservations.quantityReserved,
          reservationType: materialReservations.reservationType,
          reservedAt: materialReservations.reservedAt,
          reservedBy: materialReservations.reservedBy,
          expiresAt: materialReservations.expiresAt,
          fulfilledAt: materialReservations.fulfilledAt,
          fulfilledQuantity: materialReservations.fulfilledQuantity,
          pmTargetDate: pmSchedule.targetDate,
          trainId: pmSchedule.trainId,
          trainNumber: trains.trainNumber,
          pmTypeId: pmSchedule.pmTypeId,
          pmCode: pmTypes.pmCode,
          depotId: pmSchedule.assignedDepotId,
          depotCode: depots.code,
          depotName: depots.name,
          reservedByFirstName: users.firstName,
          reservedByLastName: users.lastName,
        })
        .from(materialReservations)
        .innerJoin(pmSchedule, eq(materialReservations.pmScheduleId, pmSchedule.id))
        .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
        .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
        .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
        .leftJoin(users, eq(materialReservations.reservedBy, users.id))
        .where(eq(materialReservations.id, id))
        .limit(1);

      if (results.length === 0) {
        throw new NotFoundError(`Reservation not found: ${id}`);
      }

      const row = results[0];

      let status: ReservationStatus;
      if (row.fulfilledAt) {
        status = 'FULFILLED';
      } else if (row.expiresAt && new Date(row.expiresAt) < now) {
        status = 'EXPIRED';
      } else {
        status = 'PENDING';
      }

      return {
        id: row.id,
        pmScheduleId: row.pmScheduleId,
        inventoryPositionId: row.inventoryPositionId,
        partNumber: row.partNumber,
        quantityReserved: row.quantityReserved,
        reservationType: row.reservationType as 'SOFT' | 'HARD',
        reservedAt: row.reservedAt?.toISOString() || '',
        reservedBy: row.reservedBy,
        reservedByName:
          row.reservedByFirstName && row.reservedByLastName
            ? `${row.reservedByFirstName} ${row.reservedByLastName}`
            : null,
        expiresAt: row.expiresAt?.toISOString() || null,
        fulfilledAt: row.fulfilledAt?.toISOString() || null,
        fulfilledQuantity: row.fulfilledQuantity,
        status,
        pm: {
          id: row.pmScheduleId,
          trainNumber: row.trainNumber,
          pmCode: row.pmCode,
          targetDate: row.pmTargetDate,
        },
        depot: {
          id: row.depotId || '',
          code: row.depotCode || '',
          name: row.depotName || '',
        },
      };
    });
  }

  /**
   * Fulfill a material reservation
   *
   * Marks the reservation as fulfilled, indicating that the materials have been
   * delivered and are ready for the PM. Optionally can specify a different fulfilled
   * quantity than reserved (partial fulfillment).
   *
   * @param request - Fulfillment request with reservation ID
   * @returns Updated reservation details
   * @throws NotFoundError if reservation not found
   * @throws ValidationError if already fulfilled or expired
   */
  async fulfillReservation(
    request: FulfillReservationRequest
  ): Promise<FulfillReservationResult> {
    return this.traced('fulfillReservation', async (span) => {
      span.setAttribute('reservation.id', request.reservationId);

      const now = new Date();

      // Get current reservation state
      const existing = await this.db
        .select()
        .from(materialReservations)
        .where(eq(materialReservations.id, request.reservationId))
        .limit(1);

      if (existing.length === 0) {
        throw new NotFoundError(`Reservation not found: ${request.reservationId}`);
      }

      const reservation = existing[0];

      // Check if already fulfilled
      if (reservation.fulfilledAt) {
        throw new ValidationError(
          'Reservation is already fulfilled',
          { context: { code: 'ALREADY_FULFILLED', reservationId: request.reservationId } }
        );
      }

      // Check if expired
      if (reservation.expiresAt && new Date(reservation.expiresAt) < now) {
        throw new ValidationError(
          'Cannot fulfill an expired reservation',
          { context: { code: 'RESERVATION_EXPIRED', reservationId: request.reservationId } }
        );
      }

      // Determine fulfilled quantity
      const fulfilledQuantity =
        request.fulfilledQuantity ?? reservation.quantityReserved;

      // Update the reservation
      await this.db
        .update(materialReservations)
        .set({
          fulfilledAt: now,
          fulfilledQuantity,
        })
        .where(eq(materialReservations.id, request.reservationId));

      this.log.info(
        {
          reservationId: request.reservationId,
          partNumber: reservation.partNumber,
          quantityReserved: reservation.quantityReserved,
          fulfilledQuantity,
        },
        'Reservation fulfilled'
      );

      return {
        id: request.reservationId,
        partNumber: reservation.partNumber,
        quantityReserved: reservation.quantityReserved,
        fulfilledQuantity,
        fulfilledAt: now.toISOString(),
        status: 'FULFILLED',
      };
    });
  }

  /**
   * Get inventory summary statistics
   *
   * Returns aggregate stats about inventory including low stock counts
   * per depot.
   */
  async getInventorySummary(): Promise<{
    totalItems: number;
    lowStockCount: number;
    byDepot: Array<{
      depotId: string;
      depotCode: string;
      itemCount: number;
      lowStockCount: number;
    }>;
  }> {
    return this.traced('getInventorySummary', async (span) => {
      // Get all inventory with depot info
      const items = await this.db
        .select({
          depotId: inventoryPositions.depotId,
          depotCode: depots.code,
          quantityOnHand: inventoryPositions.quantityOnHand,
          quantityReserved: inventoryPositions.quantityReserved,
          reorderPoint: inventoryPositions.reorderPoint,
        })
        .from(inventoryPositions)
        .innerJoin(depots, eq(inventoryPositions.depotId, depots.id));

      // Aggregate by depot
      const depotMap = new Map<
        string,
        { depotCode: string; itemCount: number; lowStockCount: number }
      >();

      let totalLowStock = 0;

      for (const item of items) {
        const available = item.quantityOnHand - item.quantityReserved;
        const isLowStock =
          item.reorderPoint !== null && available <= item.reorderPoint;

        if (isLowStock) {
          totalLowStock++;
        }

        const existing = depotMap.get(item.depotId);
        if (existing) {
          existing.itemCount++;
          if (isLowStock) existing.lowStockCount++;
        } else {
          depotMap.set(item.depotId, {
            depotCode: item.depotCode,
            itemCount: 1,
            lowStockCount: isLowStock ? 1 : 0,
          });
        }
      }

      const byDepot = Array.from(depotMap.entries()).map(([depotId, stats]) => ({
        depotId,
        ...stats,
      }));

      span.setAttribute('result.totalItems', items.length);
      span.setAttribute('result.lowStockCount', totalLowStock);

      return {
        totalItems: items.length,
        lowStockCount: totalLowStock,
        byDepot,
      };
    });
  }
}

